+cmake_minimum_required(VERSION 3.1 FATAL_ERROR)
+project(dist-mnist)
+
+find_package(Torch REQUIRED)
+
+find_package(MPI REQUIRED)
+
+include_directories(SYSTEM ${MPI_C_INCLUDE_PATH} ${MPI_CXX_INCLUDE_PATH})
+
+add_executable(dist-mnist dist-mnist.cpp)
+target_link_libraries(dist-mnist ${TORCH_LIBRARIES})
+target_link_libraries(dist-mnist ${MPI_LIBRARIES})
+
+if(MPI_COMPILE_FLAGS)
+  set_target_properties(dist-mnist PROPERTIES
+    COMPILE_FLAGS "${MPI_COMPILE_FLAGS}")
+endif()
+
+if(MPI_LINK_FLAGS)
+  set_target_properties(dist-mnist PROPERTIES
+    LINK_FLAGS "${MPI_LINK_FLAGS}")
+endif()
diff --git a/cpp/distributed/dist-mnist.cpp b/cpp/distributed/dist-mnist.cpp
new file mode 100644
index 0000000..f03cf6e
--- /dev/null
+++ b/cpp/distributed/dist-mnist.cpp
@@ -0,0 +1,201 @@
+#include <torch/torch.h>
+#include <iostream>
+#include "mpi.h"
+
+std::map<at::ScalarType, MPI_Datatype> mpiDatatype = {
+        {at::kByte, MPI_UNSIGNED_CHAR},
+        {at::kChar, MPI_CHAR},
+        {at::kDouble, MPI_DOUBLE},
+        {at::kFloat, MPI_FLOAT},
+        {at::kInt, MPI_INT},
+        {at::kLong, MPI_LONG},
+        {at::kShort, MPI_SHORT},
+};
+
+//Define a Convolutional Module
+struct Model : torch::nn::Module {
+    Model()
+          : conv1(torch::nn::Conv2dOptions(1, 10, 5)),
+            conv2(torch::nn::Conv2dOptions(10, 20, 5)),
+            fc1(320, 50),
+            fc2(50, 10) {
+        register_module("conv1", conv1);
+        register_module("conv2", conv2);
+        register_module("conv2_drop", conv2_drop);
+        register_module("fc1", fc1);
+        register_module("fc2", fc2);
+    }
+
+    torch::Tensor forward(torch::Tensor x) {
+        x = torch::relu(torch::max_pool2d(conv1->forward(x), 2));
+        x = torch::relu(torch::max_pool2d(conv2_drop->forward(conv2->forward(x)), 2));
+        x = x.view({-1, 320});
+        x = torch::relu(fc1->forward(x));
+        x = torch::dropout(x, 0.5, is_training());
+        x = fc2->forward(x);
+        return torch::log_softmax(x, 1);
+    }
+
+    torch::nn::Conv2d conv1;
+    torch::nn::Conv2d conv2;
+    torch::nn::Dropout2d conv2_drop;
+    torch::nn::Linear fc1;
+    torch::nn::Linear fc2;
+};
+
+
+int main(int argc, char *argv[])
+{
+
+  //MPI variables
+  int rank, numranks;
+  MPI_Init(&argc, &argv);
+  MPI_Comm_size(MPI_COMM_WORLD, &numranks);
+  MPI_Comm_rank(MPI_COMM_WORLD, &rank);
+  //end MPI variables
+
+  // Timer variables
+  auto tstart = 0.0;
+  auto tend = 0.0;
+
+  //TRAINING
+  //Read train dataset
+  std::string filename = "/afs/crc.nd.edu/user/s/sghosh2/Public/ML/mnist/data";
+  auto train_dataset = torch::data::datasets::MNIST(filename)
+            .map(torch::data::transforms::Normalize<>(0.1307, 0.3081))
+            .map(torch::data::transforms::Stack<>());
+
+  //Distributed Random Sampler
+  auto data_sampler = torch::data::samplers::DistributedRandomSampler(train_dataset.size().value(),
+                                             numranks, rank, false);
+
+  auto num_train_samples_per_proc = train_dataset.size().value() / numranks;
+
+  //Generate dataloader
+  auto total_batch_size = 64;
+  auto batch_size_per_proc = total_batch_size / numranks; //effective batch size in each processor 
+  auto data_loader = torch::data::make_data_loader
+                     (std::move(train_dataset), data_sampler, batch_size_per_proc);
+
+  // setting manual seed
+  torch::manual_seed(0);
+
+  auto model = std::make_shared<Model>();
+
+  auto learning_rate = 1e-2;
+
+  torch::optim::SGD optimizer(model->parameters(), learning_rate);
+
+  // Number of epochs
+  size_t num_epochs = 10;
+
+  // start timer
+  tstart = MPI_Wtime();
+
+  for (size_t epoch = 1; epoch <= num_epochs; ++epoch)
+  {
+      size_t num_correct = 0;
+
+      for (auto& batch : *data_loader)
+      {
+          auto ip = batch.data;
+          auto op = batch.target.squeeze();
+
+          //convert to required formats
+          ip = ip.to(torch::kF32);
+          op = op.to(torch::kLong);
+
+          //Reset gradients
+          model->zero_grad();
+
+          //Execute forward pass
+          auto prediction = model->forward(ip);
+
+          auto loss = torch::nll_loss(torch::log_softmax(prediction, 1) , op);
+
+          /*
+          //Print loss
+          if (rank == 0) {
+              std::cout << "Loss in epoch " << epoch << " = " << loss.item<float>() << std::endl;
+          }
+          */
+
+          //Backpropagation
+          loss.backward();
+
+          //Averaging the gradients of the parameters in all the processors
+          for (auto &param : model->named_parameters())
+          {
+              MPI_Allreduce(MPI_IN_PLACE, param.value().grad().data_ptr(),
+               param.value().grad().numel(),
+                mpiDatatype.at(param.value().grad().scalar_type()),
+                MPI_SUM, MPI_COMM_WORLD);
+
+              param.value().grad().data() = param.value().grad().data() / numranks;
+
+          }
+
+          //Update parameters
+          optimizer.step();
+
+          auto guess = prediction.argmax(1);
+          num_correct += torch::sum(guess.eq_(op)).item<int64_t>();
+      } //end batch loader
+
+      auto accuracy = 100.0 * num_correct / num_train_samples_per_proc;
+
+      std::cout << "Accuracy in rank " << rank << " in epoch " << epoch << " - " << accuracy << std::endl;
+
+   }//end epoch 
+
+   // end timer
+   tend = MPI_Wtime();
+   if (rank == 0) {
+      std::cout << "Training time - " << (tend - tstart) << std::endl;
+   }
+
+   //TESTING ONLY IN RANK 0
+   if(rank == 0)
+   {
+      auto test_dataset = torch::data::datasets::MNIST(
+                filename, torch::data::datasets::MNIST::Mode::kTest)
+                .map(torch::data::transforms::Normalize<>(0.1307, 0.3081))
+                .map(torch::data::transforms::Stack<>());
+
+      auto num_test_samples = test_dataset.size().value();
+      auto test_loader = torch::data::make_data_loader
+                     (std::move(test_dataset), num_test_samples);
+
+      model->eval(); //enable eval mode to prevent backprop
+
+      size_t num_correct = 0;
+
+      for (auto& batch : *test_loader)
+      {
+          auto ip = batch.data;
+          auto op = batch.target.squeeze();
+
+          //convert to required format
+          ip = ip.to(torch::kF32);
+          op = op.to(torch::kLong);
+
+          auto prediction = model->forward(ip);
+
+          auto loss = torch::nll_loss(torch::log_softmax(prediction, 1) , op);
+
+          std::cout << "Test loss - " << loss.item<float>() << std::endl;
+
+          auto guess = prediction.argmax(1);
+
+          num_correct += torch::sum(guess.eq_(op)).item<int64_t>();
+
+       }//end test loader
+
+       std::cout << "Num correct - " << num_correct << std::endl;
+       std::cout << "Test Accuracy - "
+                  << 100.0 * num_correct / num_test_samples << std::endl;
+   }//end rank 0 
+
+   MPI_Finalize();
+}
